VALUES
  ('social-worker-moex-02721', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在面對案主提供專業服務過程，經常會面臨進退兩難的情境，下列敘述何者錯誤？', '["屬於案主兩難的情境時，社會工作者直接將案主轉給另一位社會工作者處理", "屬於社會工作者兩難的情境時，社會工作者應具有高度敏感力，將面臨的專業價值兩難記錄並反省", "屬於案主兩難的情境時，社會工作者最好保持客觀、中立的態度", "屬於社會工作者兩難的情境時，評估此兩難是否影響專業關係的建立"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02722', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者在提供專業服務過程，必須恪守專業原則，其中有關案主自決原則係指：', '["試著了解案主的感受，並運用專業技巧，引導案主思考", "運用澄清技巧協助案主釐清所要表達的情緒、想法、意見或行為態度", "重視案主問題成因的個別差異，以及強調服務內涵的差異性", "運用沈默、減除焦慮等專業技巧，協助案主發展自我抉擇的能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02723', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '運用危機介入（crisis intervention）模式於個案工作時，應遵守的原則是：', '["被動採取行動", "注入希望與期望", "無限的工作目標", "以處理情緒為目標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02724', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Payne依照國際社會工作定義，指出社會工作者的工作有三面向，若有社會工作者說：「若可以提供協助 與服務來解決案主家庭問題，他們就可以更適當的配合社會的期待」，請問，其所使用的觀點是那一面 向？', '["治療觀點", "社會秩序觀點", "轉型觀點", "批判反思觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02725', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社會工作理論中，強調案主的不接受或逃避自由都是壞信念，應透過真誠面對，才能解放，引進人本 思想，視案主為一整體，請問該理論是：', '["解決焦點取向", "存在主義社會工作", "任務中心模型", "問題解決模型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02726', 'social-worker', 'social-worker-moex-103-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關以證據為本（evidence-based）的社會工作敘述，下列何者錯誤？', '["其緣起主要是受到以證據為本的法律學之影響", "其強調社會工作者的決策最高原則是判斷什麼是有效的", "社會工作者應有研究心態，社會工作者也是研究者", "其可使社會工作者擺脫組織限制，獲得意識形態與技術的自由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "41136ece6450", "answer_pdf_sha1": "71f6335f8306", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02727', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '被推崇為「行政管理之父」，核心主張是控制幅度明確，指揮權統一，每個工作者只有一個老闆的學者 是：', '["韋伯（Max Weber）", "費堯（Henri Fayol）", "泰勒（Frederick Winslow Taylor）", "麥格雷特（Douglas McGregor）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02728', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '目標管理（MBO）為管理學大師彼得杜拉克（Peter F. Drucker）所倡導的管理方法，係指管理者以工作 「目標」來管理部屬，其對於促進員工生產力及導引個人的工作朝向組織目標有很多幫助。目標管理係 奠基於完善的人力資源管理四項要素，下列敘述何者錯誤？', '["目標的設定，係由高層管理者設定後再指派", "目標明確化，轉化成可以衡量評估的有形指標", "目標有一個明確的完成期間", "目標管理設有回饋機制，讓員工能隨時且持續的了解目標的達成程度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02729', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「最佳價值」主張藉由持續性的改善，使經濟（economy）、效率（efficiency）與效能（effectiveness）等 功能真正發揮。為了確保這樣的改善，必須透過不同項目來檢查他們的功能。這些檢查項目的字首均為 C， 不包括下列那一項敘述？', '["質疑（challenge）為什麼、如何及為誰而提供服務", "比較（compare）不同機構之間的績效", "就教（consult）於服務的使用者及地方社區", "儘可能溝通（communication）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02730', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對方案規劃而言，有兩類型的評估：形成性評估（formative evaluation）與總結性評估（summative evaluation）。下列敘述那一項不符合形成性評估的特性？', '["在方案實際運作期間進行", "焦點在於過程目標", "回答關於方案在績效方面的問題", "確認服務是否提供給方案設計中所設定的服務對象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
